#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    char s[100005];
    while(T--){
        scanf("%s",s);
        long long a=0,b=0;
        char last='?';
        int lastPos=-1;
        int n=strlen(s);
        for(int i=0;i<n;i++){
            if(s[i]!='.'){
                if(s[i]=='A') a++; else b++;
                if(last==s[i]){
                    int dots=i-lastPos-1;
                    if(s[i]=='A') a+=dots; else b+=dots;
                }
                last=s[i];
                lastPos=i;
            }
        }
        printf("%lld %lld\n",a,b);
    }
    return 0;
}

