import sys

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    out = []
    for i in range(1, T+1):
        s = data[i].strip()
        a = b = 0
        last = None
        last_pos = -1
        for idx, ch in enumerate(s):
            if ch != '.':
                if ch == 'A':
                    a += 1
                else:
                    b += 1
                if last == ch:
                    dots = idx - last_pos - 1
                    if ch == 'A':
                        a += dots
                    else:
                        b += dots
                last = ch
                last_pos = idx
        out.append(f"{a} {b}")
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

